### 17. src/send.ts (Outbound Message Sending)

**Path:** `extensions/pulseboard/src/send.ts`

```typescript
import { resolveMarkdownTableMode } from "openclaw/plugin-sdk/config-runtime";
import { convertMarkdownTables } from "openclaw/plugin-sdk/text-runtime";

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyToId?: string;
};

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<{ messageId: string; target: string }> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(`PulseBoard is not configured for account "${account.accountId}".`);
  }

  const tableMode = resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyToId ? `${prepared}\n\n[reply:${opts.replyToId}]` : prepared;

  if (!payload.trim()) {
    throw new Error("Message must be non-empty");
  }

  // Call PulseBoard API
  const result = await callPulseBoardApi(account, {
    method: "POST",
    path: `/messages`,
    body: {
      target: to,
      text: payload,
      replyToId: opts.replyToId,
    },
  });

  recordChannelActivity(runtime, "pulseboard", account.accountId, "outbound");

  return {
    messageId: result.id,
    target: to,
  };
}
```

