### 18. src/probe.ts (Health Check)

**Path:** `extensions/pulseboard/src/probe.ts`

```typescript
import type { CoreConfig, PulseBoardProbe } from "./types.js";

export async function probePulseBoard(
  cfg: CoreConfig,
  params: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: params.accountId,
  });

  if (!account.configured) {
    return {
      status: "notConfigured",
      accountId: account.accountId,
      apiUrl: account.apiUrl,
    };
  }

  const startTime = Date.now();
  try {
    const response = await callPulseBoardApi(account, {
      method: "GET",
      path: `/health`,
      timeoutMs: params.timeoutMs,
    });

    const latencyMs = Date.now() - startTime;

    return {
      status: response.ok ? "ok" : "error",
      accountId: account.accountId,
      apiUrl: account.apiUrl,
      latencyMs,
    };
  } catch (error) {
    return {
      status: "error",
      accountId: account.accountId,
      apiUrl: account.apiUrl,
      note: error instanceof Error ? error.message : String(error),
    };
  }
}
