export function normalizePulseBoardMessagingTarget(input: string): string | null {
  const trimmed = input.trim().toLowerCase();

  if (!trimmed) {
    return null;
  }

  // Validate target format (e.g., user-123, board-456)
  if (/^[a-z0-9\-]+$/.test(trimmed)) {
    return trimmed;
  }

  return null;
}

export function looksLikePulseBoardTargetId(input: string): boolean {
