### 11. src/accounts.ts (Account Resolution)

**Path:** `extensions/pulseboard/src/accounts.ts`

This file handles account resolution, merging default config with account-specific config:

```typescript
import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
import { tryReadSecretFileSync } from "openclaw/plugin-sdk/core";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  configured: boolean;
  token: string;
  tokenSource: "env" | "tokenFile" | "config" | "none";
  apiUrl: string;
  config: PulseBoardAccountConfig;
};

const { listAccountIds: listPulseBoardAccountIds, resolveDefaultAccountId: resolveDefaultPulseBoardAccountId } =
  createAccountListHelpers("pulseboard", { normalizeAccountId });

export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

function resolvePulseBoardToken(accountId: string, merged: PulseBoardAccountConfig): {
  token: string;
  source: "env" | "tokenFile" | "config" | "none";
} {
  // Check env variables for default account
  if (accountId === DEFAULT_ACCOUNT_ID) {
    const envToken = process.env.PULSEBOARD_TOKEN?.trim();
    if (envToken) {
      return { token: envToken, source: "env" };
    }
  }

  // Check token file
  if (merged.tokenFile?.trim()) {
    const fileToken = tryReadSecretFileSync(merged.tokenFile, "PulseBoard token file", {
      rejectSymlink: true,
    });
    if (fileToken) {
      return { token: fileToken, source: "tokenFile" };
    }
  }

  // Check config
  if (merged.token?.trim()) {
    return { token: merged.token, source: "config" };
  }

  return { token: "", source: "none" };
}

export function resolvePulseBoardAccount({
  cfg,
  accountId = DEFAULT_ACCOUNT_ID,
}: {
  cfg: CoreConfig;
  accountId?: string;
}): ResolvedPulseBoardAccount {
  const merged = resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as Record<string, Partial<PulseBoardAccountConfig>> | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });

  const { token, source } = resolvePulseBoardToken(accountId, merged);
  const apiUrl = merged.apiUrl || "https://api.pulseboard.io";

  return {
    accountId: normalizeAccountId(accountId),
    enabled: merged.enabled !== false,
    name: merged.name,
    configured: Boolean(token),
    token,
    tokenSource: source,
    apiUrl,
    config: merged,
  };
}
```

