### 15. src/monitor.ts (Inbound Message Polling)

**Path:** `extensions/pulseboard/src/monitor.ts`

This file runs a background loop that polls for incoming messages:

```typescript
import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import type { RuntimeEnv } from "./runtime-api.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(`PulseBoard is not configured.`);
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let isRunning = true;
  const pollInterval = 1000;  // Poll every second

  const pollMessages = async () => {
    while (isRunning && !opts.abortSignal?.aborted) {
      try {
        // Fetch new messages from API
        const messages = await fetchNewMessages(account);

        for (const msg of messages) {
          const handled = await handlePulseBoardInbound({
            message: msg,
            account,
            runtime: core,
            onMessage: opts.onMessage,
            statusSink: opts.statusSink,
          });
          if (!handled) {
            logger.warn(`Failed to handle inbound message: ${msg.messageId}`);
          }
        }
      } catch (error) {
        logger.error(`Error polling messages: ${error}`);
      }

      await new Promise((resolve) => setTimeout(resolve, pollInterval));
    }
  };

  pollMessages().catch((error) => {
    logger.error(`Monitor error: ${error}`);
  });

  return {
    stop: () => {
      isRunning = false;
    },
  };
}
```

