import type { PulseBoardChannelConfig } from "./types.js";

export function resolvePulseBoardGroupMatch(params: {
  groups?: Record<string, PulseBoardChannelConfig>;
  target: string;
}): {
  groupConfig: PulseBoardChannelConfig | undefined;
  wildcardConfig: PulseBoardChannelConfig | undefined;
} {
  const config = params.groups?.[params.target];
  const wildcardConfig = params.groups?.["*"];
  return {
    groupConfig: config,
    wildcardConfig,
  };
}

export function resolvePulseBoardRequireMention(params: {
  groupConfig: PulseBoardChannelConfig | undefined;
  wildcardConfig: PulseBoardChannelConfig | undefined;
}): boolean {
  return params.groupConfig?.requireMention ?? params.wildcardConfig?.requireMention ?? true;
}
