      message: "API URL (optional, default: https://api.pulseboard.io)",
      initialValue: "https://api.pulseboard.io",
    });

    // Save configuration
    config = await updatePulseBoardToken(config, token.trim());
    config = await updatePulseBoardApiUrl(config, apiUrl.trim());

    return config;
  },
