27	export function resolveZaloAccount(params: {
28	  cfg: OpenClawConfig;
29	  accountId?: string | null;
30	  allowUnresolvedSecretRef?: boolean;
31	}): ResolvedZaloAccount {
32	  const accountId = normalizeAccountId(params.accountId);
33	  const baseEnabled = (params.cfg.channels?.zalo as ZaloConfig | undefined)?.enabled !== false;
34	  const merged = mergeZaloAccountConfig(params.cfg, accountId);
35	  const accountEnabled = merged.enabled !== false;
36	  const enabled = baseEnabled && accountEnabled;
37	  const tokenResolution = resolveZaloToken(
38	    params.cfg.channels?.zalo as ZaloConfig | undefined,
39	    accountId,
40	    { allowUnresolvedSecretRef: params.allowUnresolvedSecretRef },
41	  );
42	
43	  return {
44	    accountId,
45	    name: merged.name?.trim() || undefined,
46	    enabled,
47	    token: tokenResolution.token,
48	    tokenSource: tokenResolution.source,
49	    config: merged,
50	  };
51	}
