184	function startPollingLoop(params: ZaloPollingLoopParams) {
185	  const {
186	    token,
187	    account,
188	    config,
189	    runtime,
190	    core,
191	    abortSignal,
192	    isStopped,
193	    mediaMaxMb,
194	    statusSink,
195	    fetcher,
196	  } = params;
197	  const pollTimeout = 30;
198	  const processingContext = {
199	    token,
200	    account,
201	    config,
202	    runtime,
203	    core,
204	    mediaMaxMb,
205	    statusSink,
206	    fetcher,
207	  };
208	
209	  runtime.log?.(`[${account.accountId}] Zalo polling loop started timeout=${String(pollTimeout)}s`);
210	
211	  const poll = async () => {
212	    if (isStopped() || abortSignal.aborted) {
213	      return;
214	    }
215	
216	    try {
217	      const response = await getUpdates(token, { timeout: pollTimeout }, fetcher);
218	      if (response.ok && response.result) {
219	        statusSink?.({ lastInboundAt: Date.now() });
220	        await processUpdate({
221	          update: response.result,
222	          ...processingContext,
223	        });
224	      }
225	    } catch (err) {
226	      if (err instanceof ZaloApiError && err.isPollingTimeout) {
227	        // no updates
228	      } else if (!isStopped() && !abortSignal.aborted) {
229	        runtime.error?.(`[${account.accountId}] Zalo polling error: ${formatZaloError(err)}`);
230	        await new Promise((resolve) => setTimeout(resolve, 5000));
231	      }
232	    }
233	
234	    if (!isStopped() && !abortSignal.aborted) {
235	      setImmediate(poll);
236	    }
237	  };
238	
239	  void poll();
240	}
