242	async function processUpdate(params: ZaloUpdateProcessingParams): Promise<void> {
243	  const { update, token, account, config, runtime, core, mediaMaxMb, statusSink, fetcher } = params;
244	  const { event_name, message } = update;
245	  const sharedContext = { token, account, config, runtime, core, statusSink, fetcher };
246	  if (!message) {
247	    return;
248	  }
249	
250	  switch (event_name) {
251	    case "message.text.received":
252	      await handleTextMessage({
253	        message,
254	        ...sharedContext,
255	      });
256	      break;
257	    case "message.image.received":
258	      await handleImageMessage({
259	        message,
260	        ...sharedContext,
261	        mediaMaxMb,
262	      });
263	      break;
264	    case "message.sticker.received":
265	      logVerbose(core, runtime, `[${account.accountId}] Received sticker from ${message.from.id}`);
266	      break;
267	    case "message.unsupported.received":
268	      logVerbose(
269	        core,
270	        runtime,
271	        `[${account.accountId}] Received unsupported message type from ${message.from.id}`,
272	      );
273	      break;
274	  }
275	}
