337	async function authorizeZaloMessage(
338	  params: ZaloMessagePipelineParams,
339	): Promise<ZaloMessageAuthorizationResult | undefined> {
340	  const { message, account, config, runtime, core, text, mediaPath, token, statusSink, fetcher } =
341	    params;
342	  const pairing = createChannelPairingController({
343	    core,
344	    channel: "zalo",
345	    accountId: account.accountId,
346	  });
347	  const { from, chat } = message;
348	
349	  const isGroup = chat.chat_type === "GROUP";
350	  const chatId = chat.id;
351	  const senderId = from.id;
352	  const senderName = from.display_name ?? from.name;
353	
354	  const dmPolicy = account.config.dmPolicy ?? "pairing";
355	  const configAllowFrom = (account.config.allowFrom ?? []).map((v) => String(v));
356	  const configuredGroupAllowFrom = (account.config.groupAllowFrom ?? []).map((v) => String(v));
357	  const groupAllowFrom =
358	    configuredGroupAllowFrom.length > 0 ? configuredGroupAllowFrom : configAllowFrom;
359	  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
360	  const groupAccess = isGroup
361	    ? evaluateZaloGroupAccess({
362	        providerConfigPresent: config.channels?.zalo !== undefined,
363	        configuredGroupPolicy: account.config.groupPolicy,
364	        defaultGroupPolicy,
365	        groupAllowFrom,
366	        senderId,
367	      })
368	    : undefined;
369	  if (groupAccess) {
370	    warnMissingProviderGroupPolicyFallbackOnce({
371	      providerMissingFallbackApplied: groupAccess.providerMissingFallbackApplied,
372	      providerKey: "zalo",
373	      accountId: account.accountId,
374	      log: (message) => logVerbose(core, runtime, message),
375	    });
376	    if (!groupAccess.allowed) {
377	      if (groupAccess.reason === "disabled") {
378	        logVerbose(core, runtime, `zalo: drop group ${chatId} (groupPolicy=disabled)`);
379	      } else if (groupAccess.reason === "empty_allowlist") {
380	        logVerbose(
381	          core,
382	          runtime,
383	          `zalo: drop group ${chatId} (groupPolicy=allowlist, no groupAllowFrom)`,
384	        );
385	      } else if (groupAccess.reason === "sender_not_allowlisted") {
386	        logVerbose(core, runtime, `zalo: drop group sender ${senderId} (groupPolicy=allowlist)`);
387	      }
388	      return;
389	    }
390	  }
391	
392	  const rawBody = text?.trim() || (mediaPath ? "<media:image>" : "");
393	  const { senderAllowedForCommands, commandAuthorized } =
394	    await resolveSenderCommandAuthorizationWithRuntime({
395	      cfg: config,
396	      rawBody,
397	      isGroup,
398	      dmPolicy,
399	      configuredAllowFrom: configAllowFrom,
400	      configuredGroupAllowFrom: groupAllowFrom,
401	      senderId,
402	      isSenderAllowed: isZaloSenderAllowed,
403	      readAllowFromStore: pairing.readAllowFromStore,
404	      runtime: core.channel.commands,
405	    });
406	
407	  const directDmOutcome = resolveDirectDmAuthorizationOutcome({
408	    isGroup,
409	    dmPolicy,
410	    senderAllowedForCommands,
411	  });
412	  if (directDmOutcome === "disabled") {
413	    logVerbose(core, runtime, `Blocked zalo DM from ${senderId} (dmPolicy=disabled)`);
414	    return;
415	  }
416	  if (directDmOutcome === "unauthorized") {
417	    if (dmPolicy === "pairing") {
418	      await pairing.issueChallenge({
419	        senderId,
420	        senderIdLine: `Your Zalo user id: ${senderId}`,
421	        meta: { name: senderName ?? undefined },
422	        onCreated: () => {
423	          logVerbose(core, runtime, `zalo pairing request sender=${senderId}`);
424	        },
425	        sendPairingReply: async (text) => {
426	          await sendMessage(
427	            token,
428	            {
429	              chat_id: chatId,
430	              text,
431	            },
432	            fetcher,
433	          );
434	          statusSink?.({ lastOutboundAt: Date.now() });
435	        },
436	        onReplyError: (err) => {
437	          logVerbose(core, runtime, `zalo pairing reply failed for ${senderId}: ${String(err)}`);
438	        },
439	      });
440	    } else {
441	      logVerbose(
442	        core,
443	        runtime,
444	        `Blocked unauthorized zalo sender ${senderId} (dmPolicy=${dmPolicy})`,
445	      );
446	    }
447	    return;
448	  }
449	
450	  return {
451	    chatId,
452	    commandAuthorized,
453	    isGroup,
454	    rawBody,
455	    senderId,
456	    senderName,
457	  };
458	}
