460	async function processMessageWithPipeline(params: ZaloMessagePipelineParams): Promise<void> {
461	  const {
462	    message,
463	    token,
464	    account,
465	    config,
466	    runtime,
467	    core,
468	    text,
469	    mediaPath,
470	    mediaType,
471	    statusSink,
472	    fetcher,
473	    authorization: authorizationOverride,
474	  } = params;
475	  const { message_id, date } = message;
476	  const authorization =
477	    authorizationOverride ??
478	    (await authorizeZaloMessage({
479	      ...params,
480	      mediaPath,
481	      mediaType,
482	    }));
483	  if (!authorization) {
484	    return;
485	  }
486	  const { isGroup, chatId, senderId, senderName, rawBody, commandAuthorized } = authorization;
487	
488	  const { route, buildEnvelope } = resolveInboundRouteEnvelopeBuilderWithRuntime({
489	    cfg: config,
490	    channel: "zalo",
491	    accountId: account.accountId,
492	    peer: {
493	      kind: isGroup ? ("group" as const) : ("direct" as const),
494	      id: chatId,
495	    },
496	    runtime: core.channel,
497	    sessionStore: config.session?.store,
498	  });
499	
500	  if (
501	    isGroup &&
502	    core.channel.commands.isControlCommandMessage(rawBody, config) &&
503	    commandAuthorized !== true
504	  ) {
505	    logVerbose(core, runtime, `zalo: drop control command from unauthorized sender ${senderId}`);
506	    return;
507	  }
508	
509	  const fromLabel = isGroup ? `group:${chatId}` : senderName || `user:${senderId}`;
510	  const { storePath, body } = buildEnvelope({
511	    channel: "Zalo",
512	    from: fromLabel,
513	    timestamp: date ? date * 1000 : undefined,
514	    body: rawBody,
515	  });
516	
517	  const ctxPayload = core.channel.reply.finalizeInboundContext({
518	    Body: body,
519	    BodyForAgent: rawBody,
520	    RawBody: rawBody,
521	    CommandBody: rawBody,
522	    From: isGroup ? `zalo:group:${chatId}` : `zalo:${senderId}`,
523	    To: `zalo:${chatId}`,
524	    SessionKey: route.sessionKey,
525	    AccountId: route.accountId,
526	    ChatType: isGroup ? "group" : "direct",
527	    ConversationLabel: fromLabel,
528	    SenderName: senderName || undefined,
529	    SenderId: senderId,
530	    CommandAuthorized: commandAuthorized,
531	    Provider: "zalo",
532	    Surface: "zalo",
533	    MessageSid: message_id,
534	    MediaPath: mediaPath,
535	    MediaType: mediaType,
536	    MediaUrl: mediaPath,
537	    OriginatingChannel: "zalo",
538	    OriginatingTo: `zalo:${chatId}`,
539	  });
540	
541	  await core.channel.session.recordInboundSession({
542	    storePath,
543	    sessionKey: ctxPayload.SessionKey ?? route.sessionKey,
544	    ctx: ctxPayload,
545	    onRecordError: (err) => {
546	      runtime.error?.(`zalo: failed updating session meta: ${String(err)}`);
547	    },
548	  });
549	
550	  const tableMode = core.channel.text.resolveMarkdownTableMode({
551	    cfg: config,
552	    channel: "zalo",
553	    accountId: account.accountId,
554	  });
555	  const { onModelSelected, ...replyPipeline } = createChannelReplyPipeline({
556	    cfg: config,
557	    agentId: route.agentId,
558	    channel: "zalo",
559	    accountId: account.accountId,
560	    typing: {
561	      start: async () => {
562	        await sendChatAction(
563	          token,
564	          {
565	            chat_id: chatId,
566	            action: "typing",
567	          },
568	          fetcher,
569	          ZALO_TYPING_TIMEOUT_MS,
570	        );
571	      },
572	      onStartError: (err) => {
573	        logTypingFailure({
574	          log: (message) => logVerbose(core, runtime, message),
575	          channel: "zalo",
576	          action: "start",
577	          target: chatId,
578	          error: err,
579	        });
580	      },
581	    },
582	  });
583	
584	  await core.channel.reply.dispatchReplyWithBufferedBlockDispatcher({
585	    ctx: ctxPayload,
586	    cfg: config,
587	    dispatcherOptions: {
588	      ...replyPipeline,
589	      deliver: async (payload) => {
590	        await deliverZaloReply({
591	          payload,
592	          token,
593	          chatId,
594	          runtime,
595	          core,
596	          config,
597	          accountId: account.accountId,
598	          statusSink,
599	          fetcher,
600	          tableMode,
601	        });
