654	export async function monitorZaloProvider(options: ZaloMonitorOptions): Promise<void> {
655	  const {
656	    token,
657	    account,
658	    config,
659	    runtime,
660	    abortSignal,
661	    useWebhook,
662	    webhookUrl,
663	    webhookSecret,
664	    webhookPath,
665	    statusSink,
666	    fetcher: fetcherOverride,
667	  } = options;
668	
669	  const core = getZaloRuntime();
670	  const effectiveMediaMaxMb = account.config.mediaMaxMb ?? DEFAULT_MEDIA_MAX_MB;
671	  const fetcher = fetcherOverride ?? resolveZaloProxyFetch(account.config.proxy);
672	  const mode = useWebhook ? "webhook" : "polling";
673	
674	  let stopped = false;
675	  const stopHandlers: Array<() => void> = [];
676	  let cleanupWebhook: (() => Promise<void>) | undefined;
677	
678	  const stop = () => {
679	    if (stopped) {
680	      return;
681	    }
682	    stopped = true;
683	    for (const handler of stopHandlers) {
684	      handler();
685	    }
686	  };
687	
688	  runtime.log?.(
689	    `[${account.accountId}] Zalo provider init mode=${mode} mediaMaxMb=${String(effectiveMediaMaxMb)}`,
690	  );
691	
692	  try {
693	    if (useWebhook) {
694	      if (!webhookUrl || !webhookSecret) {
695	        throw new Error("Zalo webhookUrl and webhookSecret are required for webhook mode");
696	      }
697	      if (!webhookUrl.startsWith("https://")) {
698	        throw new Error("Zalo webhook URL must use HTTPS");
699	      }
700	      if (webhookSecret.length < 8 || webhookSecret.length > 256) {
701	        throw new Error("Zalo webhook secret must be 8-256 characters");
702	      }
703	
704	      const path = resolveWebhookPath({ webhookPath, webhookUrl, defaultPath: null });
705	      if (!path) {
706	        throw new Error("Zalo webhookPath could not be derived");
707	      }
708	
709	      runtime.log?.(
710	        `[${account.accountId}] Zalo configuring webhook path=${path} target=${describeWebhookTarget(webhookUrl)}`,
711	      );
712	      await setWebhook(token, { url: webhookUrl, secret_token: webhookSecret }, fetcher);
713	      let webhookCleanupPromise: Promise<void> | undefined;
714	      cleanupWebhook = async () => {
715	        if (!webhookCleanupPromise) {
716	          webhookCleanupPromise = (async () => {
717	            runtime.log?.(`[${account.accountId}] Zalo stopping; deleting webhook`);
718	            try {
719	              await deleteWebhook(token, fetcher, WEBHOOK_CLEANUP_TIMEOUT_MS);
720	              runtime.log?.(`[${account.accountId}] Zalo webhook deleted`);
721	            } catch (err) {
722	              const detail =
723	                err instanceof Error && err.name === "AbortError"
724	                  ? `timed out after ${String(WEBHOOK_CLEANUP_TIMEOUT_MS)}ms`
725	                  : formatZaloError(err);
726	              runtime.error?.(`[${account.accountId}] Zalo webhook delete failed: ${detail}`);
727	            }
728	          })();
729	        }
730	        await webhookCleanupPromise;
731	      };
732	      runtime.log?.(`[${account.accountId}] Zalo webhook registered path=${path}`);
733	
734	      const unregister = registerZaloWebhookTarget({
735	        token,
736	        account,
737	        config,
738	        runtime,
739	        core,
740	        path,
741	        secret: webhookSecret,
742	        statusSink: (patch) => statusSink?.(patch),
743	        mediaMaxMb: effectiveMediaMaxMb,
744	        fetcher,
745	      });
746	      stopHandlers.push(unregister);
747	      await waitForAbortSignal(abortSignal);
748	      return;
749	    }
750	
751	    runtime.log?.(`[${account.accountId}] Zalo polling mode: clearing webhook before startup`);
752	    try {
753	      try {
754	        const currentWebhookUrl = normalizeWebhookUrl(
755	          (await getWebhookInfo(token, fetcher)).result?.url,
756	        );
757	        if (!currentWebhookUrl) {
758	          runtime.log?.(`[${account.accountId}] Zalo polling mode ready (no webhook configured)`);
759	        } else {
760	          runtime.log?.(
761	            `[${account.accountId}] Zalo polling mode disabling existing webhook ${describeWebhookTarget(currentWebhookUrl)}`,
762	          );
763	          await deleteWebhook(token, fetcher);
764	          runtime.log?.(`[${account.accountId}] Zalo polling mode ready (webhook disabled)`);
765	        }
766	      } catch (err) {
767	        if (err instanceof ZaloApiError && err.errorCode === 404) {
768	          // Some Zalo environments do not expose webhook inspection for polling bots.
769	          runtime.log?.(
770	            `[${account.accountId}] Zalo polling mode webhook inspection unavailable; continuing without webhook cleanup`,
771	          );
772	        } else {
773	          throw err;
774	        }
775	      }
776	    } catch (err) {
777	      runtime.error?.(
778	        `[${account.accountId}] Zalo polling startup could not clear webhook: ${formatZaloError(err)}`,
779	      );
780	    }
781	
782	    startPollingLoop({
783	      token,
784	      account,
785	      config,
786	      runtime,
787	      core,
788	      abortSignal,
789	      isStopped: () => stopped,
790	      mediaMaxMb: effectiveMediaMaxMb,
791	      statusSink,
792	      fetcher,
793	    });
794	
795	    await waitForAbortSignal(abortSignal);
796	  } catch (err) {
797	    runtime.error?.(
798	      `[${account.accountId}] Zalo provider startup failed mode=${mode}: ${formatZaloError(err)}`,
799	    );
800	    throw err;
801	  } finally {
802	    await cleanupWebhook?.();
803	    stop();
804	    runtime.log?.(`[${account.accountId}] Zalo provider stopped mode=${mode}`);
805	  }
806	}
