101	/**
102	 * Call the Zalo Bot API
103	 */
104	export async function callZaloApi<T = unknown>(
105	  method: string,
106	  token: string,
107	  body?: Record<string, unknown>,
108	  options?: { timeoutMs?: number; fetch?: ZaloFetch },
109	): Promise<ZaloApiResponse<T>> {
110	  const url = `${ZALO_API_BASE}/bot${token}/${method}`;
111	  const controller = new AbortController();
112	  const timeoutId = options?.timeoutMs
113	    ? setTimeout(() => controller.abort(), options.timeoutMs)
114	    : undefined;
115	  const fetcher = options?.fetch ?? fetch;
116	
117	  try {
118	    const response = await fetcher(url, {
119	      method: "POST",
120	      headers: {
121	        "Content-Type": "application/json",
122	      },
123	      body: body ? JSON.stringify(body) : undefined,
124	      signal: controller.signal,
125	    });
126	
127	    const data = (await response.json()) as ZaloApiResponse<T>;
128	
129	    if (!data.ok) {
130	      throw new ZaloApiError(
131	        data.description ?? `Zalo API error: ${method}`,
132	        data.error_code,
133	        data.description,
134	      );
135	    }
136	
137	    return data;
138	  } finally {
139	    if (timeoutId) {
140	      clearTimeout(timeoutId);
141	    }
142	  }
143	}
