import type {
  BaseProbeResult,
  BlockStreamingCoalesceConfig,
  DmConfig,
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
  MarkdownConfig,
  OpenClawConfig,
} from "./runtime-api.js";

export type PulseBoardBoardConfig = {
  /** Require an @mention of the bot before processing a board message. Default: true. */
  requireMention?: boolean;
  /** Tool policy for messages from this board. */
  tools?: GroupToolPolicyConfig;
  /** Per-sender tool policy overrides. */
  toolsBySender?: GroupToolPolicyBySenderConfig;
  /** Skill filter applied to replies from this board. */
  skills?: string[];
  /** Whether this board entry is active. Default: true. */
  enabled?: boolean;
  /** Override allowFrom for this specific board. */
  allowFrom?: Array<string | number>;
  /** Override system prompt for this board. */
  systemPrompt?: string;
};

export type PulseBoardAccountConfig = {
  /** Optional human-readable label for this account. */
  name?: string;
  /** Whether this account is active. Default: true. */
  enabled?: boolean;
  /** PulseBoard API token. */
  apiToken?: string;
  /** Path to a file containing the API token. */
  tokenFile?: string;
  /** Override the PulseBoard REST API base URL. Default: https://api.pulseboard.example. */
  apiUrl?: string;
  /** Direct-message access policy. Default: pairing. */
  dmPolicy?: DmPolicy;
  /** Allowlist of PulseBoard user handles or IDs for DMs. */
  allowFrom?: Array<string | number>;
  /** Per-DM sender configuration. */
  dms?: Record<string, DmConfig>;
  /** Board (group) access policy. Default: allowlist. */
  boardPolicy?: GroupPolicy;
  /** Allowlist of board names for group access (falls back to allowFrom when unset). */
  boardAllowFrom?: Array<string | number>;
  /** Per-board configuration keyed by board name (use "*" for wildcard). */
  boards?: Record<string, PulseBoardBoardConfig>;
  /** Markdown rendering configuration. */
  markdown?: MarkdownConfig;
  /** Maximum inbound attachment size in MB. */
  mediaMaxMb?: number;
  /** Maximum text length per outbound chunk. Default: 4000. */
  textChunkLimit?: number;
  /** Chunking strategy: "length" splits at char limit, "newline" prefers line boundaries. */
  chunkMode?: "length" | "newline";
  /** Enable block-streaming coalescing for long replies. */
  blockStreaming?: boolean;
  /** Block-streaming coalesce configuration. */
  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
  /** Outbound reply prefix override for this account. */
  responsePrefix?: string;
};

export type PulseBoardConfig = PulseBoardAccountConfig & {
  /** Named sub-accounts (multi-account support). */
  accounts?: Record<string, PulseBoardAccountConfig>;
  /** Default account ID when multiple accounts are configured. */
  defaultAccount?: string;
};

export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

export type PulseBoardTokenSource = "env" | "config" | "configFile" | "none";

/** A single message event received from the PulseBoard polling endpoint. */
export type PulseBoardUpdate = {
  /** Unique message ID assigned by PulseBoard. */
  id: string;
  /**
   * Routing target as returned by the API:
   * - Board messages: "#<boardName>" (e.g. "#general")
   * - Direct messages: "@<botHandle>" (the bot's own handle)
   */
  target: string;
  /** Sender information. */
  from: {
    id: string;
    handle: string;
    name?: string;
  };
  /** Raw text body of the message. */
  text: string;
  /** Unix timestamp in milliseconds. */
  timestamp: number;
  /** Whether this message was sent to a board ("board") or directly ("direct"). */
  type: "board" | "direct";
};

/**
 * Normalised inbound message passed between monitor → inbound handler.
 * Board messages use the board name as target; DMs use the sender handle.
 */
export type PulseBoardInboundMessage = {
  messageId: string;
  /** Conversation target: board name for groups, sender handle for DMs. */
  target: string;
  /** Raw API target as returned by PulseBoard (e.g. "#general" or "@bot"). */
  rawTarget: string;
  senderHandle: string;
  senderId: string;
  senderName?: string;
  text: string;
  timestamp: number;
  isGroup: boolean;
};

export type PulseBoardProbe = BaseProbeResult<string> & {
  /** Resolved API base URL used during the probe. */
  apiUrl: string;
  /** Round-trip latency in milliseconds (present when probe succeeded). */
  latencyMs?: number;
  /** Handle of the authenticated bot user. */
  botHandle?: string;
};

