import {
  buildChannelConfigSchema,
  BlockStreamingCoalesceSchema,
  DmConfigSchema,
  DmPolicySchema,
  GroupPolicySchema,
  MarkdownConfigSchema,
  ReplyRuntimeConfigSchemaShape,
  ToolPolicySchema,
  requireOpenAllowFrom,
} from "openclaw/plugin-sdk/channel-config-schema";
import { z } from "openclaw/plugin-sdk/zod";
import { pulseBoardBoardConfigUiHints } from "./config-ui-hints.js";

/** Per-board (group) configuration schema. */
const PulseBoardBoardSchema = z
  .object({
    requireMention: z.boolean().optional(),
    tools: ToolPolicySchema,
    toolsBySender: z.record(z.string(), ToolPolicySchema).optional(),
    skills: z.array(z.string()).optional(),
    enabled: z.boolean().optional(),
    allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    systemPrompt: z.string().optional(),
  })
  .strict();

const PulseBoardAccountSchemaBase = z
  .object({
    name: z.string().optional(),
    enabled: z.boolean().optional(),
    apiToken: z.string().optional(),
    tokenFile: z.string().optional(),
    apiUrl: z.string().url().optional(),
    dmPolicy: DmPolicySchema.optional().default("pairing"),
    allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    dms: z.record(z.string(), DmConfigSchema.optional()).optional(),
    boardPolicy: GroupPolicySchema.optional().default("allowlist"),
    boardAllowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    boards: z.record(z.string(), PulseBoardBoardSchema.optional()).optional(),
    markdown: MarkdownConfigSchema,
    mediaMaxMb: z.number().optional(),
    textChunkLimit: z.number().int().positive().optional(),
    chunkMode: z.enum(["length", "newline"]).optional(),
    blockStreaming: z.boolean().optional(),
    blockStreamingCoalesce: BlockStreamingCoalesceSchema.optional(),
    responsePrefix: z.string().optional(),
    ...ReplyRuntimeConfigSchemaShape,
  })
  .strict();

const PulseBoardAccountSchema = PulseBoardAccountSchemaBase.superRefine((value, ctx) => {
  requireOpenAllowFrom({
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    path: ["allowFrom"],
    message: 'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardConfigSchema = PulseBoardAccountSchemaBase.extend({
  accounts: z.record(z.string(), PulseBoardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
}).superRefine((value, ctx) => {
  requireOpenAllowFrom({
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    path: ["allowFrom"],
    message: 'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema, {
  uiHints: pulseBoardBoardConfigUiHints,
});

