/**
 * Minimal HTTP client for the fictional PulseBoard REST API.
 *
 * All endpoints are rooted at <apiUrl>/v1 and authenticate via
 * `Authorization: Bearer <token>`.
 *
 * @see https://docs.pulseboard.example/api (fictional)
 */

export const PULSEBOARD_TEXT_CHUNK_LIMIT = 4000;

export class PulseBoardApiError extends Error {
  constructor(
    message: string,
    public readonly statusCode?: number,
    public readonly code?: string,
  ) {
    super(message);
    this.name = "PulseBoardApiError";
  }

  /** True when the server returned HTTP 401 (invalid/expired token). */
  get isUnauthorized(): boolean {
    return this.statusCode === 401;
  }
}

export type PulseBoardBotInfo = {
  id: string;
  handle: string;
  name?: string;
};

export type PulseBoardPollResponse = {
  /** Messages received since the requested cursor, oldest-first. */
  messages: PulseBoardPollMessage[];
  /** Opaque cursor to pass as `since` on the next poll. */
  nextSince: number;
};

export type PulseBoardPollMessage = {
  id: string;
  /** Routing target: "#<boardName>" for boards, "@<botHandle>" for DMs. */
  target: string;
  from: {
    id: string;
    handle: string;
    name?: string;
  };
  text: string;
  /** Unix timestamp in milliseconds. */
  timestamp: number;
  type: "board" | "direct";
};

export type PulseBoardSendResult = {
  id: string;
  target: string;
};

type PulseBoardRequestOptions = {
  method: "GET" | "POST";
  path: string;
  body?: Record<string, unknown>;
  timeoutMs?: number;
  token: string;
  apiUrl: string;
};

async function callPulseBoardApi<T>(opts: PulseBoardRequestOptions): Promise<T> {
  const url = `${opts.apiUrl.replace(/\/$/, "")}/v1${opts.path}`;
  const controller = new AbortController();
  const timeoutId = opts.timeoutMs
    ? setTimeout(() => controller.abort(), opts.timeoutMs)
    : undefined;

  try {
    const response = await fetch(url, {
      method: opts.method,
      headers: {
        Authorization: `Bearer ${opts.token}`,
        "Content-Type": "application/json",
        Accept: "application/json",
      },
      body: opts.body !== undefined ? JSON.stringify(opts.body) : undefined,
      signal: controller.signal,
    });

    if (!response.ok) {
      let code: string | undefined;
      try {
        const errorBody = (await response.json()) as { code?: string; message?: string };
        code = errorBody.code;
      } catch {
        // Ignore parse failures on error responses.
      }
      throw new PulseBoardApiError(
        `PulseBoard API error ${response.status} on ${opts.method} ${opts.path}`,
        response.status,
        code,
      );
    }

    return (await response.json()) as T;
  } catch (err) {
    if (err instanceof PulseBoardApiError) {
      throw err;
    }
    if (err instanceof Error && err.name === "AbortError") {
      throw new PulseBoardApiError(
        `PulseBoard request timed out after ${opts.timeoutMs ?? "?"}ms`,
        undefined,
        "TIMEOUT",
      );
    }
    throw err;
  } finally {
    if (timeoutId !== undefined) {
      clearTimeout(timeoutId);
    }
  }
}

/**
 * Verify the API token and return the authenticated bot info.
 * Used for probing and setup validation.
 */
export async function getPulseBoardMe(params: {
  token: string;
  apiUrl: string;
  timeoutMs?: number;
}): Promise<PulseBoardBotInfo> {
  return callPulseBoardApi<PulseBoardBotInfo>({
    method: "GET",
    path: "/me",
    token: params.token,
    apiUrl: params.apiUrl,
    timeoutMs: params.timeoutMs,
  });
}

/**
 * Long-poll for new messages since `since` (Unix ms cursor).
 * Returns up to `limit` messages (default 50) and an updated cursor.
 */
export async function pollPulseBoardMessages(params: {
  token: string;
  apiUrl: string;
  since: number;
  limit?: number;
  timeoutMs?: number;
}): Promise<PulseBoardPollResponse> {
  const query = new URLSearchParams({
    since: String(params.since),
    limit: String(params.limit ?? 50),
  });
  return callPulseBoardApi<PulseBoardPollResponse>({
    method: "GET",
    path: `/messages/poll?${query.toString()}`,
    token: params.token,
    apiUrl: params.apiUrl,
    timeoutMs: params.timeoutMs ?? 35_000,
  });
}

/**
 * Send a text message to a board ("#boardName") or a user ("@userHandle").
 */
export async function sendPulseBoardMessage(params: {
  token: string;
  apiUrl: string;
  target: string;
  text: string;
  replyToId?: string;
  timeoutMs?: number;
}): Promise<PulseBoardSendResult> {
  return callPulseBoardApi<PulseBoardSendResult>({
    method: "POST",
    path: "/messages",
    body: {
      target: params.target,
      text: params.text.slice(0, PULSEBOARD_TEXT_CHUNK_LIMIT),
      ...(params.replyToId ? { replyToId: params.replyToId } : {}),
    },
    token: params.token,
    apiUrl: params.apiUrl,
    timeoutMs: params.timeoutMs ?? 15_000,
  });
}

