import type { PulseBoardInboundMessage } from "./types.js";

/** Board names begin with "#". */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/** User handles begin with "@". */
export function isUserTarget(target: string): boolean {
  return target.startsWith("@");
}

/**
 * Normalise a user-supplied messaging target.
 *
 * Accepts:
 *   "#boardName"   → "#boardname"   (boards are case-insensitive)
 *   "@userHandle"  → "@userhandle"
 *   "pb:#boardName" / "pulseboard:#boardName" prefix variants
 *   "board:boardName" (without the leading #) → "#boardname"
 *   "user:userHandle"                          → "@userhandle"
 *
 * Returns `undefined` for empty or structurally invalid inputs.
 */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
