import { getPulseBoardMe, PulseBoardApiError } from "./api.js";
import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = {
    ok: false,
    apiUrl: account.apiUrl,
  };

  if (!account.configured) {
    return {
      ...base,
      error: "missing API token (set channels.pulseboard.apiToken or PULSEBOARD_API_TOKEN)",
    };
  }

  const started = Date.now();
  try {
    const me = await getPulseBoardMe({
      token: account.token,
      apiUrl: account.apiUrl,
      timeoutMs: opts?.timeoutMs ?? 8_000,
    });
    const latencyMs = Date.now() - started;
    return {
      ...base,
      ok: true,
      latencyMs,
      botHandle: me.handle,
    };
  } catch (err) {
    const latencyMs = Date.now() - started;
    const probe: PulseBoardProbe = {
      ...base,
      error: formatError(err),
      latencyMs,
    };
    if (err instanceof PulseBoardApiError && err.isUnauthorized) {
      probe.error = "API token rejected (HTTP 401); check channels.pulseboard.apiToken";
    }
    return probe;
  }
}

