import { resolveLoggerBackedRuntime } from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { getPulseBoardMe, pollPulseBoardMessages } from "./api.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { isBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage, PulseBoardUpdate } from "./types.js";
import type { RuntimeEnv } from "./runtime-api.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  /** Override for tests — receives the normalised message before dispatch. */
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

/** Convert a raw API update into the normalised inbound message shape. */
export function resolvePulseBoardInboundTarget(update: PulseBoardUpdate): {
  isGroup: boolean;
  target: string;
  rawTarget: string;
} {
  const rawTarget = update.target;
  if (update.type === "board" || isBoardTarget(rawTarget)) {
    // Strip the leading "#" for the canonical target key.
    const boardName = rawTarget.startsWith("#") ? rawTarget : `#${rawTarget}`;
    return { isGroup: true, target: boardName, rawTarget };
  }
  // Direct message — use sender handle as the conversation peer.
  return { isGroup: false, target: update.from.handle, rawTarget };
}

function makePulseBoardMessageId(update: PulseBoardUpdate): string {
  return update.id;
}

/**
 * Start the PulseBoard long-poll monitoring loop for one account.
 *
 * The monitor repeatedly calls `/v1/messages/poll` with a cursor that
 * advances as messages are consumed.  On abort it returns without throwing.
 *
 * @returns An object with a `stop()` method that aborts the loop.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (set channels.pulseboard.apiToken or PULSEBOARD_API_TOKEN).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  // Fetch bot identity once so we can match @<botHandle> mentions.
  let botHandle: string | undefined;
  try {
    const me = await getPulseBoardMe({ token: account.token, apiUrl: account.apiUrl });
    botHandle = me.handle;
    logger.info(
      `[${account.accountId}] connected to PulseBoard as @${me.handle} (${account.apiUrl})`,
    );
  } catch (err) {
    logger.error(`[${account.accountId}] failed to fetch bot identity: ${String(err)}`);
  }

  // Use the current time as the initial poll cursor so we only see new messages.
  let since = Date.now();

  const abortController = new AbortController();
  const combinedAbort = () => abortController.abort();
  opts.abortSignal?.addEventListener("abort", combinedAbort, { once: true });

  async function pollLoop(): Promise<void> {
    while (!abortController.signal.aborted) {
      try {
        const response = await pollPulseBoardMessages({
          token: account.token,
          apiUrl: account.apiUrl,
          since,
          // Request a generous timeout so the server can hold the connection
          // open during quiet periods (long-poll semantics).
          timeoutMs: 40_000,
        });

        since = response.nextSince;

        for (const update of response.messages) {
          if (abortController.signal.aborted) {
            break;
          }

          const inboundTarget = resolvePulseBoardInboundTarget(update);
          const message: PulseBoardInboundMessage = {
            messageId: makePulseBoardMessageId(update),
            target: inboundTarget.target,
            rawTarget: inboundTarget.rawTarget,
            senderHandle: update.from.handle,
            senderId: update.from.id,
            senderName: update.from.name,
            text: update.text,
            timestamp: update.timestamp,
            isGroup: inboundTarget.isGroup,
          };

          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "inbound",
            at: message.timestamp,
          });

          if (opts.onMessage) {
            await opts.onMessage(message);
            continue;
          }

          await handlePulseBoardInbound({
            message,
            account,
            config: cfg,
            runtime,
            botHandle,
            statusSink: opts.statusSink,
          });
        }
      } catch (err) {
        if (abortController.signal.aborted) {
          break;
        }
