import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createAllowFromSection,
  createStandardChannelSetupStatus,
  formatDocsLink,
  setSetupChannelEnabled,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { listPulseBoardAccountIds, resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardAllowEntry, normalizePulseBoardMessagingTarget } from "./normalize.js";
import {
  setPulseBoardAllowFrom,
  setPulseBoardDmPolicy,
  updatePulseBoardAccountConfig,
} from "./setup-core.js";
import type { CoreConfig } from "./types.js";

const channel = "pulseboard" as const;
const USE_ENV_FLAG = "__pbUseEnv";

function parseListInput(raw: string): string[] {
  return raw
    .split(/[\n,;]+/g)
    .map((entry) => entry.trim())
    .filter(Boolean);
}

const pulseBoardDmPolicy: ChannelSetupDmPolicy = {
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => (cfg as CoreConfig).channels?.pulseboard?.dmPolicy ?? "pairing",
  setPolicy: (cfg, policy) => setPulseBoardDmPolicy(cfg as CoreConfig, policy),
  promptAllowFrom: async ({ cfg, prompter, accountId }) => {
    const existing = (cfg as CoreConfig).channels?.pulseboard?.allowFrom ?? [];
    const currentStr = existing
      .map((e) => normalizePulseBoardAllowEntry(String(e)))
      .filter(Boolean)
      .join(", ");

    const raw = String(
      await prompter.text({
        message: "PulseBoard allowFrom (handles, comma-separated)",
        placeholder: "alice, bob",
        initialValue: currentStr || undefined,
        validate: (value) =>
          String(value ?? "").trim() ? undefined : "Enter at least one handle",
      }),
    );

    const entries = parseListInput(raw)
      .map((entry) => normalizePulseBoardAllowEntry(entry))
      .filter(Boolean);

    return setPulseBoardAllowFrom(cfg as CoreConfig, entries);
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API token",
    configuredHint: "configured",
    unconfiguredHint: "needs API token",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) =>
          resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs an API token from your PulseBoard admin console.",
      "Boards (#board-name) and direct messages (@handle) are both supported.",
      "Set channels.pulseboard.boardPolicy and channels.pulseboard.boards for group access control.",
      'By default, boards are mention-gated. Set boards["#name"].requireMention=false to disable.',
      "Env var: PULSEBOARD_API_TOKEN (default account only).",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;
    const envToken = isDefaultAccount ? process.env.PULSEBOARD_API_TOKEN?.trim() : undefined;
    const resolved = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });

    if (envToken && !resolved.config.apiToken && !resolved.config.tokenFile) {
      const useEnv = await prompter.confirm({
        message: "PULSEBOARD_API_TOKEN detected. Use env var?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "1" },
        };
      }
    }

    return {
      cfg,
      credentialValues: { ...credentialValues, [USE_ENV_FLAG]: "0" },
    };
  },
  credentials: [
    {
      inputKey: "token",
      message: "PulseBoard API token",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.apiToken
          ? "(set)"
          : undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues[USE_ENV_FLAG] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          apiToken: value,
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "apiUrl",
      message: "PulseBoard API base URL (optional)",
      placeholder: "https://api.pulseboard.example",
      required: false,
      applyEmptyValue: false,
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.apiUrl || undefined,
      validate: ({ value }) => {
        const trimmed = String(value ?? "").trim();
        if (!trimmed) {
          return undefined;
        }
        try {
          new URL(trimmed);
          return undefined;
        } catch {
          return "Enter a valid URL (e.g. https://api.pulseboard.example)";
        }
      },
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) => {
        const trimmed = String(value ?? "").trim();
        if (!trimmed) {
          return cfg;
        }
        return updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { apiUrl: trimmed });
      },
    },
    {
      inputKey: "groupChannels",
      message: "PulseBoard boards to allow (optional, comma-separated, e.g. #general, #ops)",
      placeholder: "#general, #ops, *",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) => {
        const boards = resolvePulseBoardAccount({
          cfg: cfg as CoreConfig,
          accountId,
        }).config.boards;
        if (!boards) {
          return undefined;
        }
        return Object.keys(boards).join(", ");
      },
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((entry) => {
            const normalized = normalizePulseBoardMessagingTarget(
              entry.startsWith("#") ? entry : `#${entry.replace(/^#+/, "")}`,
            );
            return normalized ?? entry.toLowerCase().trim();
          })
          .filter(Boolean)
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const trimmed = String(value ?? "").trim();
        if (!trimmed) {
          return cfg;
        }
        const boardNames = parseListInput(trimmed).map((entry) =>
          entry.startsWith("#") ? entry : `#${entry.replace(/^#+/, "")}`,
        );
        const boards = Object.fromEntries(boardNames.map((name) => [name, {}]));
        return updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          boardPolicy: "allowlist",
          boards,
        });
      },
    },
  ],
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard DM allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by sender handle.",
      "Examples:",
      "- alice",
      "- @bob",
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (handle)",
    placeholder: "alice, @bob",
    invalidWithoutCredentialNote: "Use a PulseBoard user handle (e.g. alice or @alice).",
    parseId: (raw) => {
      const normalized = normalizePulseBoardAllowEntry(raw);
      return normalized || null;
    },
    apply: async ({ cfg, allowFrom }) => setPulseBoardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart the gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

