      inputKey: "groupChannels",
      message: "PulseBoard boards to allow (optional, comma-separated, e.g. #general, #ops)",
      placeholder: "#general, #ops, *",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) => {
        const boards = resolvePulseBoardAccount({
          cfg: cfg as CoreConfig,
          accountId,
        }).config.boards;
        if (!boards) {
          return undefined;
        }
        return Object.keys(boards).join(", ");
      },
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((entry) => {
            const normalized = normalizePulseBoardMessagingTarget(
              entry.startsWith("#") ? entry : `#${entry.replace(/^#+/, "")}`,
            );
            return normalized ?? entry.toLowerCase().trim();
          })
          .filter(Boolean)
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const trimmed = String(value ?? "").trim();
        if (!trimmed) {
          return cfg;
        }
        const boardNames = parseListInput(trimmed).map((entry) =>
          entry.startsWith("#") ? entry : `#${entry.replace(/^#+/, "")}`,
