// Private runtime barrel for the bundled PulseBoard extension.
// Keep this barrel thin and aligned with the local extension surface.
//
// NOTE: In a full repo integration a companion src/plugin-sdk/pulseboard.ts
// would consolidate these imports under a single public SDK surface and this
// file would simply re-export from `openclaw/plugin-sdk/pulseboard`, matching
// the pattern of other bundled channels (irc, nostr, zalo, etc.).
//
// Until that SDK file is committed, we import from individual public SDK
// subpaths. The one exception is `dispatchInboundReplyWithBase`, which is not
// yet surfaced on a generic public path — it is temporarily bootstrapped from
// the IRC SDK surface and must be moved to `openclaw/plugin-sdk/pulseboard`
// when that file is created.

export {
  buildChannelConfigSchema,
  getChatChannelMeta,
  PAIRING_APPROVED_MESSAGE,
  DEFAULT_ACCOUNT_ID,
} from "openclaw/plugin-sdk/channel-plugin-common";

export {
  buildBaseChannelStatusSummary,
  createComputedAccountStatusAdapter,
  createDefaultChannelRuntimeState,
} from "openclaw/plugin-sdk/status-helpers";

export {
  createAccountStatusSink,
} from "openclaw/plugin-sdk/channel-lifecycle";

export {
  chunkMarkdownTextWithMode,
  resolveTextChunkLimit,
} from "openclaw/plugin-sdk/reply-chunking";

export {
  createChannelPairingController,
} from "openclaw/plugin-sdk/channel-pairing";

export {
  deliverFormattedTextWithAttachments,
} from "openclaw/plugin-sdk/reply-payload";

export {
  GROUP_POLICY_BLOCKED_LABEL,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveDefaultGroupPolicy,
  warnMissingProviderGroupPolicyFallbackOnce,
} from "openclaw/plugin-sdk/runtime-group-policy";

export {
  logInboundDrop,
} from "openclaw/plugin-sdk/channel-inbound";

export {
  readStoreAllowFromForDmPolicy,
  resolveEffectiveAllowFromLists,
} from "openclaw/plugin-sdk/security-runtime";

export {
  resolveControlCommandGate,
} from "openclaw/plugin-sdk/command-auth";

// TODO(bootstrap): move to `openclaw/plugin-sdk/pulseboard` once that SDK
// surface file is created alongside this plugin. The IRC surface exports the
// same function from the same internal module.
export {
  dispatchInboundReplyWithBase,
} from "openclaw/plugin-sdk/irc";

export type {
  BaseProbeResult,
} from "openclaw/plugin-sdk/channel-contract";

export type {
  ChannelPlugin,
  PluginRuntime,
} from "openclaw/plugin-sdk/channel-plugin-common";

export type { OpenClawConfig } from "openclaw/plugin-sdk/core";

export type { RuntimeEnv } from "openclaw/plugin-sdk/runtime-env";

export type {
  OutboundReplyPayload,
} from "openclaw/plugin-sdk/reply-payload";

// Group/DM policy types are spread across several SDK subpaths.
export type {
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
} from "openclaw/plugin-sdk/channel-policy";

export type {
  DmPolicy,
  GroupPolicy,
} from "openclaw/plugin-sdk/setup";

export type {
  BlockStreamingCoalesceConfig,
  DmConfig,
  MarkdownConfig,
} from "openclaw/plugin-sdk/channel-config-schema";

